const Q_COMMERCE_1998=[{"id": "objective>Commerce>1998>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following contributed least to the evolution of commercial activities in Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Development of banks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Development of transportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Development of trader's unions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Development of currencies</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The development of trader's unions contributed least to the evolution of commercial activities in Nigeria. The development of banks, transportation, and currencies had a more direct and significant impact on commercial activities. Banks provide the necessary financial services for commerce, transportation facilitates the movement of goods and services, and currencies enable transactions. Trader's unions, while important, do not have as direct or broad an impact on commercial activities as the other options.</div>", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE"}, {"id": "objective>Commerce>1998>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the factors which critically determines the choice of occupation is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Training</div>", "<div style=\"font-family:Cambria;font-size:17px;\">skills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aptitude</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Interest refers to a person's enthusiasm or inclination towards a particular field or activity. It plays a crucial role in guiding individuals towards occupations that they find personally fulfilling and enjoyable. <br/>  <br/> Interest often serves as the primary motivation for pursuing a specific career path. It reflects one's passion and willingness to invest time and effort into developing the necessary skills and expertise for a particular occupation.</div>", "topic": "OCCUPATION : MEANING & IMPORTANCE"}, {"id": "objective>Commerce>1998>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Extractive industries may also be denominated as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Direct industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Servicing industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Primary industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indirect industries</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The extractive industries are those engage in obtaining raw materials and natural resources from the soil or sea. It is also referred to as the primary stage of production e.g farming, fishing, mining etc.</div>", "topic": "OCCUPATION : TYPES OF OCCUPATION"}, {"id": "objective>Commerce>1998>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary objective of a business organization is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cater for the needs of its owners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">work towards making returns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Assist the government to serve the citizens</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Improve the standard of living of its proprietors</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary objective of any business is to earn a profit. Profit is necessary for growing and expanding business activities.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : BUSINESS RESOURCES"}, {"id": "objective>Commerce>1998>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Service which are of absolute monopoly can can best be provided by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Private companies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Limited liability companies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Public companies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Public enterprises</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Services that are of absolute monopoly are best provided by public enterprises. An absolute monopoly is a market structure where a single entity is the only provider of a particular good or service. Public enterprises are government-owned entities that are often established to provide essential public services, including those that are natural monopolies. A natural monopoly occurs when a single firm can serve the entire market demand at a lower cost than any combination of two or more firms. This is often the case with utilities like water, electricity, and public transportation.</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES"}, {"id": "objective>Commerce>1998>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One advantage the co-operative society has over the company is that the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The latter pays tax while the former does not</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Former attract more capitals than the later</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Members of the former is usually more than the latter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Former, unlike the latter, has limited liabilities</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary objective of a cooperative society is not to make profit but to attain the common goal of its members. One of the advantage is that Cooperative societies are exempted from paying taxes in most of the states, since their primary interest is not necessarily profit-making.</div>", "topic": "BUSINESS UNIT: PARTNERSHIP : ADVANTAGES AND DISADVANTAGES"}, {"id": "objective>Commerce>1998>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the above information below to answer question below <br/> Mr obi is a manager of obi Agricultural Venture. He makes all the decisions and takes all profits from the business. He had agreed with Alhaji Musa. It can be deduce from the above that obi Agricultural Venture is (a farmer) to pool their resources together and expand their business.They invited Mr Abayomi (a cotton grower) to join them. Mr Abayami agreed on the condition that his liability in the new firm will be limited to his investment in it. They thus registered Obi, Musa and Abayaomi's Agricultural ventures. <br/>  <br/> It can be deduced from the above that obi agricultural venture is ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sole proprietorship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">general partnership</div>", "<div style=\"font-family:Cambria;font-size:17px;\">limited partnership</div>", "<div style=\"font-family:Cambria;font-size:17px;\">joint venture</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The business is a sole proprietorship since Mr Obi is the owner of the business is the business is not converted to any other form of business.</div>", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES"}, {"id": "objective>Commerce>1998>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the above information below to answer question below <br/> Mr obi is a manager of obi Agricultural Venture. He makes all the decisions and takes all profits from the business. He had agreed with Alhaji Musa. It can be deduce from the above that obi Agricultural Venture is (a farmer) to pool their resources together and expand their business.They invited Mr Abayomi (a cotton grower) to join them. Mr Abayami agreed on the condition that his liability in the new firm will be limited to his investment in it. They thus registered Obi, Musa and Abayaomi's Agricultural ventures. <br/> which of the statements below is true of Mr. Abayomi? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">he can assign his shares to another without consent of other partners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">He cannot take part in the management of the business</div>", "<div style=\"font-family:Cambria;font-size:17px;\">His actions as a limited partner can bind the firm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">His death will automatically dissolve partnership</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the information given, Mr. Abayomi agreed to join the venture on the condition that his liability in the new firm will be limited to his investment in it. This is characteristic of a limited partner in a limited partnership. A limited partner is an investor who does not have management control and cannot be held liable for more than their investment in the partnership. Therefore, the correct answer is 'He cannot take part in the management of the business'.</div>", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES"}, {"id": "objective>Commerce>1998>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A source of capital to private limited companies is shares issued to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the public </div>", "<div style=\"font-family:Cambria;font-size:17px;\">selected person</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Members of the board of directors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Members of the board of shareholders</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A private company is normally restricted to issuing shares to its members, to staff and their families and to debenture holders. However, by private arrangement, the company may issue shares to anyone it chooses. Shares in a private limited company may only be sold or transferred with the permission of the directors.</div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>1998>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an example of a conglomerate?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">National Electric Power Authority</div>", "<div style=\"font-family:Cambria;font-size:17px;\">United Africa Company Nigeria Plc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Nigeria Railway Corporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">First Bank of Nigeria Plc</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Conglomerate is the combination of two or more business entities engaged in either entirely different or similar businesses that fall under one corporate group, usually involving a parent company and many subsidiaries.</div>", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER"}, {"id": "objective>Commerce>1998>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statement is true of preferred stockholders?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They have no voting rights at annual general meetings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They first claim company asset before creditors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The have first claim to company asset after all debts have been settled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They share dividends equally with common shareholders</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Preferred stockholders generally do not have voting rights, as common stockholders do, but they have a greater claim to the company's assets.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE"}, {"id": "objective>Commerce>1998>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A provision in the charter of a company which gives holders of common stock the first option to purchase additional issues of the firm's common stock is known the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pre-emptive right</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shareholders right</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ex-dividend right</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Over-subscription right</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pre-emptive right give a shareholder the opportunity to buy additional shares in any future issue of a company's common stock before the shares are made available to the general public.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE"}, {"id": "objective>Commerce>1998>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this questions below <br/>  <br/> SONU ENTERPRISES <br/> Balance Sheet as at 31/3/98 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">#</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital </td><td style=\"border:1px solid black;text-align:center;\">6000.00</td><td style=\"border:1px solid black;text-align:center;\"> Plant/Machinery</td><td style=\"border:1px solid black;text-align:center;\"> 2300.00</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Net profit</td><td style=\"border:1px solid black;text-align:center;\"> 2000.00</td><td style=\"border:1px solid black;text-align:center;\"> Motor van </td><td style=\"border:1px solid black;text-align:center;\">2000.00</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">drawings</td><td style=\"border:1px solid black;text-align:center;\">(137.50)</td><td style=\"border:1px solid black;text-align:center;\"> Stock </td><td style=\"border:1px solid black;text-align:center;\">1250.00</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors </td><td style=\"border:1px solid black;text-align:center;\">1000.00</td><td style=\"border:1px solid black;text-align:center;\"> debtors </td><td style=\"border:1px solid black;text-align:center;\">480.00</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Accruals</td><td style=\"border:1px solid black;text-align:center;\"> 187.50</td><td style=\"border:1px solid black;text-align:center;\"> Bank </td><td style=\"border:1px solid black;text-align:center;\">3000.00</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">Cash </td><td style=\"border:1px solid black;text-align:center;\">20.00</td></tr></table></div> <br/>  <br/> What is the current ratio?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.5:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25.5:1</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Current ratio = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">Current asset</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> Current liabilities</span> <br/>  <br/> Current assets = stock + debtors + bank + cash <br/>  = 1250 + 480 + 3000 + 20 <br/> = 4750 <br/>  <br/> Current liabilities = creditors + Accruals <br/> = 1000 + 187.50 <br/> = 1187.5 <br/>  <br/> Current ratio = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">4750</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">1187.5</span> <br/>  <br/> = 4/1 =  4: 1</div>", "topic": "FINANCING BUSINESS : TURNOVER"}, {"id": "objective>Commerce>1998>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this questions below <br/>  <br/> SONU ENTERPRISES <br/> Balance Sheet as at 31/3/98 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">#</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital </td><td style=\"border:1px solid black;text-align:center;\">6000.00</td><td style=\"border:1px solid black;text-align:center;\"> Plant/Machinery</td><td style=\"border:1px solid black;text-align:center;\"> 2300.00</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Net profit</td><td style=\"border:1px solid black;text-align:center;\"> 2000.00</td><td style=\"border:1px solid black;text-align:center;\"> Motor van </td><td style=\"border:1px solid black;text-align:center;\">2000.00</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">drawings</td><td style=\"border:1px solid black;text-align:center;\">(137.50)</td><td style=\"border:1px solid black;text-align:center;\"> Stock </td><td style=\"border:1px solid black;text-align:center;\">1250.00</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors </td><td style=\"border:1px solid black;text-align:center;\">1000.00</td><td style=\"border:1px solid black;text-align:center;\"> debtors </td><td style=\"border:1px solid black;text-align:center;\">480.00</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Accruals</td><td style=\"border:1px solid black;text-align:center;\"> 187.50</td><td style=\"border:1px solid black;text-align:center;\"> Bank </td><td style=\"border:1px solid black;text-align:center;\">3000.00</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">Cash </td><td style=\"border:1px solid black;text-align:center;\">20.00</td></tr></table></div> <br/> What is the acid ratio?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.95:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.25:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.75:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.55:1</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">=   <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">Current assets - Stock</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> Current liabilities</span> <br/>  <br/> = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">4750 - 1250</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> 1187.5</span> <br/>  <br/> = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">3500</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">1187.5</span> <br/>  <br/> = 2.95 : 1</div>", "topic": "FINANCING BUSINESS : TURNOVER"}, {"id": "objective>Commerce>1998>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The form of capital which is easily transferred into the form desired is known as?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Working capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liquid capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">circulating capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital employed</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Liquid capital is any capital that can be easily transform to a desired form e.g cash, bank, debtors etc.</div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>1998>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a firm's turnover is N15,000 and the cost of goods sold is N 10,000 What is the percentage of gross profit on sales?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">23.3%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">33.3%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50.0%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">66.6%</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gross profit = Turnover/ sales - Cost of goods sold <br/>  = 15,000 - 10,000 <br/> = #5,000 <br/>  <br/> Gross profit on sales = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">Gross profit </span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> Sales</span>  x 100 <br/>  <br/>   = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">5000</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">15000 </span> x 100 <br/>  <br/> =  33.3% <br/> </div>", "topic": "FINANCING BUSINESS : PROFIT"}, {"id": "objective>Commerce>1998>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A machine which enable sales without the physical presence of a sales attendant is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">computer machine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vending machine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">telex machine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fax machine</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vending machine is a machine from which products are sold. The customer puts money in a slot, selects a product from the menu and the product is dispensed from the machine.</div>", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE"}, {"id": "objective>Commerce>1998>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What document is required when a country imposes ad valorem import duties on goods?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> A mail transfer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A shipping note</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A bill of lading</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A consular invoice</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main purpose of a consular invoice is to provide a complete and detailed description of the goods to the foreign customs authority, so as to ensure that the correct import duty is levied on the goods</div>", "topic": "TRADE ( 2) : DOCMENT USED IN INTERNATION TRADE"}, {"id": "objective>Commerce>1998>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Entre port trade is said to have taken place when goods are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Held at the port payment of custom duty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sold in the ship under special regulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Imported and then re-export</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kept for further processing before sales</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Entre port refers to a port, or warehouse where goods are imported to be stored or traded for re-export.</div>", "topic": "TRADE ( 2) : FOREIGN TRADE"}, {"id": "objective>Commerce>1998>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a price is quoted at F.O.B it means that the price?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">excludes loading charges incurred in bringing the goods to port of destination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exclude all necessary shipping charges payable for insurance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">includes all charges payable on shipping a consignment to the port destination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">includes charges payable for loading goods onto the ship</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">F.O.B (Free On Board) is a term in international commercial law specifying at what point respective obligations, costs, and risk involved in the delivery of goods shift from the seller to the buyer. When a price is quoted at FOB, it means that the price includes charges payable for loading goods onto the ship. It does not exclude loading charges incurred in bringing the goods to port of destination, exclude all necessary shipping charges payable for insurance, or include all charges payable on shipping a consignment to the port destination.</div>", "topic": "TRADE ( 2) : DOCMENT USED IN INTERNATION TRADE"}, {"id": "objective>Commerce>1998>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Emeka ordered goods for his retail shop. The manufacturer sells the goods at retail price of #500 but would give it to Emeka at #400. What kind of discount did he get?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cash discount </div>", "<div style=\"font-family:Cambria;font-size:17px;\">trade discount </div>", "<div style=\"font-family:Cambria;font-size:17px;\">quantity discount</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seasonal discount </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A trade discount is a reduction in price given by a manufacturer or wholesaler to a retailer. In this case, Emeka is a retailer who is given a reduction in price by the manufacturer. Therefore, the kind of discount he got is a trade discount.</div>", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE"}, {"id": "objective>Commerce>1998>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Postal Services (NIPOST) facilitates commerce in all the following ways except through </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cash on delivery service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recorded delivery service</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> express service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">free on board service</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NIPOST helps to make the remittance of trade values in terms of money order, postal order stamps, and financial services more convenient. Nigeria's postal service (NIPOST) is one of the nation's core industry that needs to be urgently upgraded to be more productive, efficient and customer responsive.</div>", "topic": "AIDS TO TRADE: COMMUNICATION : ADVANTAGES & DISADVANTAGES"}, {"id": "objective>Commerce>1998>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The document with which a manufacturing enterprises releases stock of raw materials to the factory for product is called?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Stock releases form</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Goods received note</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stock issues voucher</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Material release note</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A materials release note is a document used by manufacturing enterprises to release stock of raw materials from the warehouse or strong area to the factory for production. It serves as an authorization for the movement of materials and typically includes details such as the type of materials, quantity released, date, and any relevant instructions or references. This document helps ensure proper inventory management and control within the manufacturing process.</div>", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE"}, {"id": "objective>Commerce>1998>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The two main categories under which marine losses fall into are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Particular loss and average loss</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Actual loss and average loss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Total loss and partial loss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Voyage policy loss and time policy loss</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marine losses can be categorised into total loss ( which is subdivided into: actual and constructive loss) and partial loss ( which is divided into: general average loss and particular average loss).</div>", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES"}, {"id": "objective>Commerce>1998>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Insurance companies operate on the principal of indemnity. This means that an insured person or firm collector</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Only half of the loss suffered</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Double the value of the losses suffered</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The total sum of the premium paid prior to the loss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Damage claims equal to the loss suffered.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Indemnity is the compensation given to the insured by the insurer in the event of his suffering a loss. Under this principle, the insured will be given compensation for loss suffered and he will be restored to his former position before the loss ocurred.</div>", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES"}, {"id": "objective>Commerce>1998>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important difference between community banks and peoples' bank is that the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Latter is owned solely by government while the former are not</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Former cater for ruler dwellers while the latter cater for both rural and urban dwellers</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Former are service oriented while the latter are profit oriented</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Latter advances loans to the public while former advance loans to the rural dwellers only.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main difference between community banks and people's banks is in their ownership structure. Community banks are typically owned by the community members and operate for the benefit of the community. On the other hand, people's banks are government-owned institutions. Therefore, the latter is owned solely by the government while the former are not.</div>", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK"}, {"id": "objective>Commerce>1998>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The assets, liabilities and general management of a distressed bank may be taken over by?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">International Bank for Reconstruction and Development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria Industrial Development Bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria Banks Deposit Insurance Corporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria Bank for Commerce and Industry</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria Banks Deposit Insurance Corporation is an independent agency of the Federal Government of Nigeria. The purpose of the deposit insurance system is to protect depositors and guarantee the settlement of insured funds when a deposit-taking financial institution can no longer repay their deposits, thereby helping to maintain financial system stability.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>1998>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of securities that the stock exchange deals with are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Warrants, currency notes, money orders and postal orders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cheques, bank drafts , warrants and promissory notes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bonds ivory, treasure bills, debentures and warrants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stocks, shares, bonds and warrants.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The stock exchange primarily deals with securities such as stocks, shares, bonds and warrants. Stocks and shares represent ownership in a company, bonds are debt securities issued by companies or governments to raise capital, and warrants are derivatives that give the holder the right to buy the underlying security at a specific price, on or before a certain date.</div>", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES"}, {"id": "objective>Commerce>1998>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">i. Companies must be registered as private limited liability companies. <br/> ii. Companies must not have less than 100 shareholders <br/> iii. No shareholder may have more than 75% of issued shared capital.  <br/>  <br/> Which of the above are requirements for admission into the second-tier securities market?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> I and ii only.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and iii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, ii and iii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii and iii only.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The requirement for admission are: <br/> - the company must be incorporated as a public limited liability company under the Companies Act 1968 <br/> - the shareholders must not less than 100 <br/> - the company must sign a general undertaking with the stock exchange market <br/> - the company must make available, at least 10% of its equity share to the investing public <br/> - the financial statements of the company for three years must be submitted to the stock exchange <br/> - any investor or shareholder will not be allowed to either directly or indirectly acquire more than 75% of the issued capital.</div>", "topic": "STOCK EXCHANGE : SECOND- TIER SECURITIES MARKET"}, {"id": "objective>Commerce>1998>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An underlined principle in the marketing of goods is that firms should</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Train their personnel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be consumers oriented</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Advertise the goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sell through outlets</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Every business needs a marketing strategy. It introduces the company's goods and services to potential customers and informs existing ones of additional opportunities to buy.</div>", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT"}, {"id": "objective>Commerce>1998>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Product X was introduced into the market at N4.00 with its cost of product at N3.90 while competing products are at N4.50. What pricing policy are producers of X adopting?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Market skimming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Market penetration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Product live promotion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Above the market pricing</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Market penetration is defined as a measurement, is the assessment of how much a product is being sold relative to the total estimated market for that product, expressed as a percentage. It involves reducing the price in the market in order to gain instant dominance in the market. </div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>1998>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oral presentation in a conversation with one or more prospective buyers for the purpose of making sales is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Branding of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Personal selling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">packaging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">publicity</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Personal selling involves the direct personal contact of sellers with the potential buyers with view to making sales. It can also be referred to as the face-to-face meeting of the salesmen with the potential buyers in their houses, offices, or market place e.g door-to-door selling.</div>", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE"}, {"id": "objective>Commerce>1998>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Personnel activities that promote the general image of an organization are part of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Advertising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sales promotion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">public relations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Business correspondence</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Public relations is the image building done by an organisation to give the public favourable impression about its aims and policies.</div>", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE"}, {"id": "objective>Commerce>1998>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An agent must not make any secret profit in the performance of his duties but can be rewarded by his principal through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Remuneration and indemnity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Payments of commission and salary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Granting of business concessions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Forwarding of business links</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An agent must not make secret profit and he if does, the principal must be aware. However, the principal can pay the agent the commission or other agreed remuneration, indemnify the agent for any expenses of losses incurred by the agents, provide all necessary facilities to the agent for proper execution of the contract.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT"}, {"id": "objective>Commerce>1998>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sabo and Gambo entered into a contract for the sale of two baskets of tomatoes belonging to Gambo. Before the date the date of delivery and without any default by Gambo, the tomatoes were stolen. This is an example of termination of contract by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Breach</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Performance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fault</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Frustration</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A contract can be discharged when the subject matter or basis of the contract has been destroyed or frustrated by an act of God e.g accident,flood, war etc.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT"}, {"id": "objective>Commerce>1998>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A minor is not permitted to enter into a valid contract because he</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cannot pay the consideration</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Is too young to interpret the law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Is young in the eye of the law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">May not be able to write the contract</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Minor is an infant who is under 18 years of age. A contract entered with an infant or minor is not valid in the court of law.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT"}, {"id": "objective>Commerce>1998>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A person who is cheated in business transaction can seek legal remedy</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> Even if the agreement is verbal and the amount involved is large</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Only if the business is a sole proprietorship whose owner is known</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Regardless of the form of business organization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Only if the transaction is documented in a contract</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A person who is cheated in a business transaction can seek legal remedy regardless of the form of business organization. This is because the law protects all individuals in business transactions, whether they are dealing with a sole proprietorship, a partnership, a corporation, or any other form of business organization. The key factor is not the form of the business, but whether a legal wrong has been committed.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : REMEDIES FOR A BREACH OF CONTRACT"}, {"id": "objective>Commerce>1998>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most essential element of a product is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">utility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">design</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colour</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Satisfaction (utility) is the most essential element of a product because customer satisfaction is a clear indicator of product success and should be an on going goal not only to keep clients satisfied.</div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>1998>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a disadvantage of nationalization</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It promotes poor economic planning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The cost of services is not determined by by market forces</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It may lead to rationalization of resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The development of local skills and technology is retarded</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The development of local skills and technology is retarded: Nationalization may impede the development of local skills and technology in several ways. When industries are nationalized, the government often takes control of operations, which can result in a centralized decision-making process that may not prioritize innovation, research, and development. This can lead to a lack of investment in technological advancements and a reduced focus on developing local talent and expertise. Additionally, nationalized industries may face bureaucratic inefficiencies and rigidities that hinder the adoption of new technologies and practices.</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVATAGES"}, {"id": "objective>Commerce>1998>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a consumer protection agency is the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> Nigeria Bar association</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria Medical Association</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Federal Environmental Protection Agency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturers Association of Nigeria</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Consumer protection agency means any government authority that regulates, administers or enforces consumer protection law. Federal Environmental Protection Agency is an example of consumer protection agency.</div>", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : REGULATORY AGENCIES"}, {"id": "objective>Commerce>1998>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The body that organizes, promotes and participates in local and foreign trade fairs is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ministry of Commerce and Tourism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ministry of finance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chambers of Commerce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Export promotion council</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chamber of commerce is to organise trade fairs in order to promote their businesses to the customers and help to promote home and foreign trade etc.</div>", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE"}, {"id": "objective>Commerce>1998>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Continental West African Conference is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Group of all West African countries trading in the same products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Conference to foster unity among the West African countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Groups of shipping lines operating on the same West African route</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trust with shareholders from all West African countries</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Continental West African Conference (CWAC) is an international organization founded in 1999 to promote trade and economic cooperation among West African countries. It has 15 member states: Benin, Burkina Faso, Cape Verde, Côte d'Ivoire, Gambia, Ghana, Guinea, Guinea-Bissau, Liberia, Mali, Mauritania, Niger, Nigeria, Senegal, and Sierra Leone.</div>", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC."}, {"id": "objective>Commerce>1998>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main function of thrift, credit and loans co-operative societies is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Educate their members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Collect money from their members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Disburse money to their members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Raise investment finance among their members</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Thrift, credit and loans co-operative societies are financial institutions that are owned and operated by their members. The main function of these societies is to collect savings from their members and then lend these savings back to their members in the form of loans. Therefore, the correct answer is 'Disburse money to their members'.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>1998>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Management is described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Getting things done through people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Implementing of business decision</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The numbers of levels in an organization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The people in authority in an organization</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Mary Paker Follett, Management can be defined as the art of getting things done through people.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : MEANING AND TYPES"}, {"id": "objective>Commerce>1998>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under normal circumstances, a business enterprise can be ideally structured</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">By product, function or territories</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Around the personalities in the enterprise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">On the ruling of the management</div>", "<div style=\"font-family:Cambria;font-size:17px;\">On the basis of an order from stockholders</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Under normal circumstances, a business enterprise can be ideally structured according to product, function or territories <br/> </div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>1998>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the following sequences can best fit into the structure above?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">People-control-ideals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Material-production-ideas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Finance-marketing-production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Material-production-product</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Material-production-product fits into the structure of the business environment</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : BUSINESS RESOURCES"}, {"id": "objective>Commerce>1998>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a business enterprise provides free service to its environment, the service is said to be a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Civic responsibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Philanthropic consideration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Social responsibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Political consideration</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A business enterprises is not profit oriented alone; it is also set up to contribute to the welfare of the people in its environment.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : MEANING AND TYPES"}, {"id": "objective>Commerce>1998>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Inventory control is an aspect of a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Operations research</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Materials management</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the organizing function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">span of control</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Inventory control also called stock control is the process of ensuring the right amount of supply available in an organization. With appropriate internal and production controls, the practice ensures the company can meet customer demand and delivers financial elasticity.</div>", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE"}, {"id": "objective>Commerce>1998>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reduction of import duties among the members countries of ECOWAS is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> Preference duties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Preferential treatment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Preferential tariff</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Preferential excise</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Preferential tariff is one that falls under a preferential trade agreement. Basically, countries make a deal in which they agree to charge  a lower rate.</div>", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC."}, {"id": "objective>Commerce>1998>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a common market, member countries agree basically to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Place bans on the other countries' products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wage war against other countries' product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Establish common barriers against countries outside the market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Negotiate with countries outside the market for favourable terms of trade.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Common market also known as Economic community is a form of co-operation in which there is common internal and external tariff policy. There is free mobility of labour and capital between member states.</div>", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC."}];
